/**
 * Tool-invocation rule registry — the "memory → runtime defense" bridge.
 *
 * Each rule encodes a known-bad invocation of a built-in CC tool (Agent,
 * Bash, Read, Write, etc.) — typically a param shape that the operator
 * (or AI) keeps reaching for because the tool description suggests it,
 * but that has a known failure mode the repo has already paid for.
 *
 * Read by `pretool/tool-invocation-linter` at PreToolUse time. When a
 * rule matches, the linter emits a non-blocking advisory pointing the
 * caller at the documented workaround.
 *
 * Adding a new rule is a 1-line registry update plus ≥ 2 unit tests
 * (enforced by `tool-invocation-rules.coverage.test.ts`).
 *
 * Why this exists: #1883 (Agent isolation:"worktree") is the seed case,
 * but #1882 / #1884 / #1885 are the same class. Each one was previously
 * a docs PR; with this framework each one is a registry entry.
 */

/** Possible severities a rule can carry. */
export type RuleSeverity = 'warn' | 'block' | 'info';

/**
 * A tool-invocation rule.
 *
 * `predicate` receives the same `tool_input` object the hook sees and
 * must be a pure function (no I/O, no side effects). Predicates that
 * throw are treated as non-matches (defensive).
 */
export interface ToolInvocationRule {
  /** Stable identifier, kebab-case, e.g. 'agent-isolation-worktree'. Used in tests. */
  id: string;
  /** Exact tool_name from HookInput, e.g. 'Agent', 'Bash', 'Read'. */
  tool_name: string;
  /** Pure predicate — returns true to flag the invocation. */
  predicate: (tool_input: Record<string, unknown>) => boolean;
  /** How loud the linter should be. v1 only uses `warn`; the others are reserved. */
  severity: RuleSeverity;
  /** Human-readable message surfaced as additionalContext. Keep ≤ 200 chars. */
  message: string;
  /** Non-empty pointer to docs or issue (e.g. 'docs/parallel-primitives.md' or '#1883'). */
  see: string;
  /**
   * Provenance tag for non-static rules, e.g. 'memory:feedback_foo.md' (#1901).
   * Static registry rules omit it; the linter appends it to the advisory so
   * operators know a rule came from user memory rather than the canonical set.
   */
  source?: string;
}

/**
 * Defensive predicate runner — pure-function rule guarantee enforced at
 * call time. If a rule's predicate throws (a bug), we log and treat as
 * non-match, so a buggy rule can never crash the linter.
 */
export function safelyMatches(
  rule: ToolInvocationRule,
  tool_input: Record<string, unknown>,
): boolean {
  try {
    return rule.predicate(tool_input) === true;
  } catch {
    return false;
  }
}

